import{_ as r,o as t,c as o,ai as s,ar as a}from"./chunks/framework.DO_cB6UY.js";const d=JSON.parse('{"title":"Group List","description":"","frontmatter":{},"headers":[],"relativePath":"Web Client/Main/Group List.md","filePath":"Web Client/Main/Group List.md"}'),i={name:"Web Client/Main/Group List.md"};function n(l,e,p,u,m,c){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="group-list" tabindex="-1">Group List <a class="header-anchor" href="#group-list" aria-label="Permalink to “Group List”">​</a></h1><p>Every instance can have multiple groups that can be used to better organize yourself and or your team or any other use case you can think of. Every group will have their own channels, icon, banner and permissions and while it may seem like a server list, it is not.</p><p><strong>Here are possible use cases for groups:</strong></p><ul><li>You could make a group for your staff members to better organize and keeping things from being messy</li><li>If you want to run a general community, you could create a group for each topic, like anime, music, gaming, etc..</li><li>You could give friends admin permissions so that they could add some roles and a group for themselves rather than hosting their own instance.</li></ul><p>While groups have their own permissions, they all share and derive from the server roles. Generally speaking, channel permissions overwrite group permissions, and group permissions overwrite server role permissions. Its important to keep in mind that groups are not fully isolated from the instance, which makes it less ideal to be used &quot;as server&quot;, as groups cannot have their own roles as of the time of writing, and its currently not planned to change.</p><p><img src="'+a+'" alt="image-20251225224807092"></p>',6)])])}const g=r(i,[["render",n]]);export{d as __pageData,g as default};
